const DATA_URL = 'data.json';
let currentData = null;
let refreshMs = (localStorage.getItem('refreshMin') || 5) * 60000;

// ── Condition info descriptions ──
const INFO = {
  discount_rate: { title: 'Discount Rate Condition', body: 'Tracks real yields, yield curve shape, and TIPS pricing. High real yields (>1.5%) are bearish for gold as they increase the opportunity cost of holding non-yielding assets. An inverted curve signals recession risk.' },
  liquidity: { title: 'Liquidity Condition', body: 'Monitors VIX, credit spreads (HYG/LQD ratio), and bond market stress via TLT. Tightening liquidity with rising VIX and widening spreads signals risk-off — mixed for gold depending on whether it acts as haven or risk asset.' },
  inflation: { title: 'Inflation Condition', body: 'Watches crude oil (WTI/Brent), TIPS, and agricultural commodities (DBA). Sticky inflation above target with rising commodity prices supports gold as an inflation hedge, especially when central banks fall behind the curve.' },
  growth: { title: 'Growth Condition', body: 'Tracks S&P 500, Nasdaq, Russell 2000 (IWM), and Industrials (XLI). Broad expansion with healthy small-caps and industrials generally means risk-on — neutral to mildly bearish for gold. Deterioration triggers haven flows.' },
  trust: { title: 'Trust / Fiat Confidence', body: 'The most powerful gold signal. Monitors gold/silver prices, miners (GDX), DXY, and currency pairs. When gold surges while the dollar weakens, it signals a breakdown in fiat confidence — the strongest bullish signal for precious metals.' }
};

const CONDITION_LABELS = {
  discount_rate: 'Discount Rate',
  liquidity: 'Liquidity',
  inflation: 'Inflation',
  growth: 'Growth',
  trust: 'Trust'
};

const STATUS_SCORES = {
  BULLISH: 1, FLUSH: 1, EXPANSION: 1, INTACT: 1,
  BEARISH: -1, TIGHTENING: -1, STICKY: 0, BREAKDOWN: 1,
  NEUTRAL: 0
};

// ── Utility ──
function fmt(v) {
  if (v === null || v === undefined) return '—';
  if (typeof v === 'string') return v;
  if (Math.abs(v) >= 1000) return v.toLocaleString('en-US', { maximumFractionDigits: 0 });
  return v.toLocaleString('en-US', { maximumFractionDigits: 2 });
}
function chgClass(v) { return v > 0 ? 'up' : v < 0 ? 'dn' : ''; }
function chgStr(v) { if (v === undefined || v === null) return ''; return (v > 0 ? '+' : '') + v.toFixed(2) + '%'; }
function statusClass(s) { return 'status-' + (s || 'neutral').toLowerCase(); }

// ── Quick Stats ──
function renderQuickStats(data) {
  const c = data.conditions;
  const items = [
    { label: 'GOLD', val: c.trust.metrics['Gold (spot)'].value, chg: c.trust.metrics['Gold (spot)'].change },
    { label: 'OIL', val: c.inflation.metrics['WTI Crude'].value, chg: c.inflation.metrics['WTI Crude'].change },
    { label: 'VIX', val: c.liquidity.metrics['VIX'].value, chg: c.liquidity.metrics['VIX'].change },
    { label: 'DXY', val: c.trust.metrics['DXY'].value, chg: c.trust.metrics['DXY'].change },
    { label: '10Y', val: c.discount_rate.metrics['10Y Yield'].value },
    { label: 'S&P', val: c.growth.metrics['S&P 500'].value, chg: c.growth.metrics['S&P 500'].change }
  ];
  document.getElementById('quick-stats').innerHTML = items.map(i =>
    `<div class="stat"><span class="label">${i.label}</span><span class="val">${i.val}</span>${i.chg !== undefined ? `<span class="chg ${chgClass(i.chg)}">${chgStr(i.chg)}</span>` : ''}</div>`
  ).join('');
}

// ── Regime Summary ──
function renderRegimeSummary(data) {
  const badge = data.action === 'BUY' ? 'badge-buy' : data.action === 'SELL' ? 'badge-sell' : 'badge-hold';
  let el = document.getElementById('regime-section');
  if (!el) { el = document.createElement('div'); el.id = 'regime-section'; document.getElementById('main-content').insertBefore(el, document.getElementById('loading')); }
  el.className = 'regime';
  el.innerHTML = `
    <div class="regime-header">
      <span class="regime-score">${data.score > 0 ? '+' : ''}${data.score}</span>
      <span class="regime-badge ${badge}">${data.action}</span>
      ${data.market_status ? `<span class="market-status">${data.market_status.label}</span>` : ''}
    </div>
    <div class="regime-text">${data.regime}</div>
    ${data.ai_summary ? `<div class="regime-summary">💡 ${data.ai_summary}</div>` : ''}
    <div style="font-size:11px;color:var(--dim);margin-top:6px">Updated: ${data.updated_display || ''}</div>`;
}

// ── Condition Cards ──
function signalStrength(status) {
  const map = { BULLISH: 90, FLUSH: 80, EXPANSION: 75, INTACT: 70, NEUTRAL: 50, STICKY: 45, TIGHTENING: 35, BEARISH: 25, BREAKDOWN: 85 };
  return map[status] || 50;
}
function signalColor(pct) { return pct >= 70 ? 'var(--green)' : pct >= 45 ? 'var(--yellow)' : 'var(--red)'; }

function renderConditionCards(data) {
  let container = document.getElementById('cards-container');
  if (!container) { container = document.createElement('div'); container.id = 'cards-container'; container.className = 'cards-grid'; document.getElementById('main-content').appendChild(container); }
  const keys = Object.keys(data.conditions);
  container.innerHTML = keys.map(key => {
    const c = data.conditions[key];
    const pct = signalStrength(c.status);
    const metrics = Object.entries(c.metrics);
    return `<div class="card">
      <div class="card-header">
        <span class="card-title">${CONDITION_LABELS[key] || key}</span>
        <span class="status-badge ${statusClass(c.status)}">${c.status}</span>
      </div>
      <div class="card-class">${c.classification}</div>
      <div class="metrics-grid">${metrics.map(([k, v]) =>
        `<div class="metric"><span class="mk">${k}</span><span class="mv">${v.value}${v.change !== undefined ? ` <span class="${chgClass(v.change)}">${chgStr(v.change)}</span>` : ''}</span></div>`
      ).join('')}</div>
      <div class="signal-bar"><div class="signal-fill" style="width:${pct}%;background:${signalColor(pct)}"></div></div>
      <button class="info-btn" onclick="showInfo('${CONDITION_LABELS[key] || key}','${INFO[key]?.body || ''}')">i</button>
    </div>`;
  }).join('');
}

// ── Fear & Greed Gauge ──
function renderGauge(data) {
  let container = document.getElementById('gauge-section');
  if (!container) { container = document.createElement('div'); container.id = 'gauge-section'; container.className = 'gauge-container'; document.getElementById('main-content').appendChild(container); }

  // Calculate fear/greed from conditions
  const conds = data.conditions;
  let score = 0, count = 0;
  Object.values(conds).forEach(c => {
    const s = STATUS_SCORES[c.status];
    if (s !== undefined) { score += s; count++; }
  });
  // Normalize to 0-100 (50 = neutral)
  const normalized = Math.round(((score / Math.max(count, 1)) + 1) * 50);
  const clamped = Math.max(0, Math.min(100, normalized));
  const label = clamped <= 20 ? 'Extreme Fear' : clamped <= 40 ? 'Fear' : clamped <= 60 ? 'Neutral' : clamped <= 80 ? 'Greed' : 'Extreme Greed';

  container.innerHTML = `<h3>Fear & Greed</h3><canvas id="gauge-canvas" width="260" height="150"></canvas><div class="gauge-label">${clamped}</div><div class="gauge-sub">${label}</div>`;

  requestAnimationFrame(() => drawGauge(clamped));
}

function drawGauge(value) {
  const canvas = document.getElementById('gauge-canvas');
  if (!canvas) return;
  const ctx = canvas.getContext('2d');
  const cx = 130, cy = 130, r = 100;
  ctx.clearRect(0, 0, 260, 150);

  // Background arc
  const gradient = ctx.createLinearGradient(0, 0, 260, 0);
  gradient.addColorStop(0, '#ff4444');
  gradient.addColorStop(0.5, '#ffcc00');
  gradient.addColorStop(1, '#00ff88');
  ctx.beginPath(); ctx.arc(cx, cy, r, Math.PI, 0); ctx.lineWidth = 18; ctx.strokeStyle = '#1f2937'; ctx.stroke();
  ctx.beginPath(); ctx.arc(cx, cy, r, Math.PI, 0); ctx.lineWidth = 14; ctx.strokeStyle = gradient; ctx.globalAlpha = 0.3; ctx.stroke(); ctx.globalAlpha = 1;

  // Value arc
  const angle = Math.PI + (value / 100) * Math.PI;
  ctx.beginPath(); ctx.arc(cx, cy, r, Math.PI, angle); ctx.lineWidth = 14; ctx.strokeStyle = gradient; ctx.stroke();

  // Needle
  const nx = cx + (r - 10) * Math.cos(angle);
  const ny = cy + (r - 10) * Math.sin(angle);
  ctx.beginPath(); ctx.arc(nx, ny, 6, 0, Math.PI * 2); ctx.fillStyle = '#fff'; ctx.fill();
  ctx.beginPath(); ctx.arc(cx, cy, 4, 0, Math.PI * 2); ctx.fillStyle = '#6366f1'; ctx.fill();
}

// ── Holdings (deferred) ──
function renderHoldings(data) {
  let container = document.getElementById('holdings-section');
  if (!container) { container = document.createElement('div'); container.id = 'holdings-section'; container.className = 'holdings'; document.getElementById('main-content').appendChild(container); }

  const saved = JSON.parse(localStorage.getItem('holdings') || 'null');
  const portfolio = data.portfolio || {};
  const tickers = saved || Object.keys(portfolio);

  const totalValue = tickers.reduce((sum, t) => {
    const p = portfolio[t];
    return p ? sum + p.price * p.shares : sum;
  }, 0);

  container.innerHTML = `<h3>Holdings <span style="font-weight:400;font-size:12px;color:var(--dim)">$${fmt(totalValue)}</span></h3>
    <div class="holdings-grid">
      ${tickers.map(t => {
        const p = portfolio[t];
        if (!p) return `<div class="holding"><span class="tk">${t}</span><span class="nm">Not found</span><button class="rm" onclick="removeHolding('${t}')">&times;</button></div>`;
        return `<div class="holding">
          <button class="rm" onclick="removeHolding('${t}')">&times;</button>
          <div class="tk">${t}</div>
          <div class="nm">${p.name}</div>
          <div class="pr">$${fmt(p.price)} × ${p.shares.toLocaleString()}</div>
          <div class="ch ${chgClass(p.change)}">${chgStr(p.change)}</div>
          <div style="font-size:11px;color:var(--dim)">$${fmt(p.price * p.shares)}</div>
        </div>`;
      }).join('')}
      <div class="add-btn" onclick="addHolding()">+</div>
    </div>`;
}

window.removeHolding = function(ticker) {
  const saved = JSON.parse(localStorage.getItem('holdings') || 'null') || Object.keys(currentData.portfolio || {});
  const updated = saved.filter(t => t !== ticker);
  localStorage.setItem('holdings', JSON.stringify(updated));
  renderHoldings(currentData);
};
window.addHolding = function() {
  const ticker = prompt('Enter ticker symbol:');
  if (!ticker) return;
  const saved = JSON.parse(localStorage.getItem('holdings') || 'null') || Object.keys(currentData.portfolio || {});
  saved.push(ticker.toUpperCase());
  localStorage.setItem('holdings', JSON.stringify(saved));
  renderHoldings(currentData);
};

// ── War Room (deferred) ──
const WAR_SLIDERS = [
  { key: 'gold', label: 'Gold', min: 1500, max: 5000, step: 50 },
  { key: 'oil', label: 'Oil', min: 40, max: 200, step: 5 },
  { key: 'vix', label: 'VIX', min: 10, max: 80, step: 1 },
  { key: 'yields', label: '10Y', min: 1, max: 7, step: 0.1 },
  { key: 'dxy', label: 'DXY', min: 85, max: 115, step: 0.5 }
];

const SCENARIOS = {
  'Risk Off': { gold: 4800, oil: 120, vix: 45, yields: 3.5, dxy: 95 },
  'Goldilocks': { gold: 2800, oil: 65, vix: 14, yields: 3.8, dxy: 103 },
  'Inflation': { gold: 4500, oil: 150, vix: 30, yields: 5.5, dxy: 98 },
  'Deflation': { gold: 3000, oil: 45, vix: 35, yields: 2.0, dxy: 108 }
};

let liveValues = {};

function renderWarRoom(data) {
  const c = data.conditions;
  liveValues = {
    gold: c.trust.metrics['Gold (spot)'].raw,
    oil: c.inflation.metrics['WTI Crude'].raw,
    vix: c.liquidity.metrics['VIX'].raw,
    yields: c.discount_rate.metrics['10Y Yield'].raw,
    dxy: c.trust.metrics['DXY'].raw
  };

  let container = document.getElementById('warroom-section');
  if (!container) { container = document.createElement('div'); container.id = 'warroom-section'; container.className = 'warroom'; document.getElementById('main-content').appendChild(container); }

  container.innerHTML = `<h3>War Room</h3>
    ${WAR_SLIDERS.map(s => {
      const live = liveValues[s.key] || ((s.min + s.max) / 2);
      return `<div class="slider-row">
        <label>${s.label}</label>
        <input type="range" id="wr-${s.key}" min="${s.min}" max="${s.max}" step="${s.step}" value="${live}" oninput="document.getElementById('wv-${s.key}').textContent=this.value">
        <span class="sv" id="wv-${s.key}">${Math.round(live * 100) / 100}</span>
      </div>`;
    }).join('')}
    <div class="scenario-btns">
      ${Object.keys(SCENARIOS).map(name => `<button onclick="applyScenario('${name}')">${name}</button>`).join('')}
      <button onclick="resetToLive()" style="border-color:var(--accent)">Reset to Live</button>
    </div>`;
}

window.applyScenario = function(name) {
  const s = SCENARIOS[name];
  if (!s) return;
  Object.entries(s).forEach(([k, v]) => {
    const el = document.getElementById('wr-' + k);
    const lbl = document.getElementById('wv-' + k);
    if (el) { el.value = v; if (lbl) lbl.textContent = v; }
  });
};
window.resetToLive = function() {
  Object.entries(liveValues).forEach(([k, v]) => {
    const el = document.getElementById('wr-' + k);
    const lbl = document.getElementById('wv-' + k);
    if (el) { el.value = v; if (lbl) lbl.textContent = Math.round(v * 100) / 100; }
  });
};

// ── News Ticker (deferred) ──
function renderNewsTicker(data) {
  if (!data.ticker_headlines || !data.ticker_headlines.length) return;
  let container = document.getElementById('ticker-section');
  if (!container) { container = document.createElement('div'); container.id = 'ticker-section'; container.className = 'ticker'; document.getElementById('main-content').appendChild(container); }
  const items = data.ticker_headlines.map(h => `<span class="ticker-item"><span class="tc">${h.condition}</span>${h.text}</span>`).join('');
  container.innerHTML = `<div class="ticker-inner">${items}${items}</div>`;
}

// ── Info Sheet ──
window.showInfo = function(title, text) {
  document.getElementById('info-title').textContent = title;
  document.getElementById('info-body').textContent = text;
  document.getElementById('info-sheet').classList.add('open');
};
window.closeInfo = function() {
  document.getElementById('info-sheet').classList.remove('open');
};
document.addEventListener('click', e => {
  if (!e.target.closest('#info-sheet') && !e.target.closest('.info-btn')) closeInfo();
});

// ── Theme Toggle ──
function applyTheme(theme) {
  document.documentElement.setAttribute('data-theme', theme);
  document.getElementById('theme-toggle').textContent = theme === 'dark' ? '🌙' : '☀️';
  localStorage.setItem('theme', theme);
}
document.getElementById('theme-toggle').addEventListener('click', () => {
  applyTheme(document.documentElement.getAttribute('data-theme') === 'dark' ? 'light' : 'dark');
});
applyTheme(localStorage.getItem('theme') || 'dark');

// ── Settings ──
document.getElementById('settings-toggle').addEventListener('click', () => {
  document.getElementById('settings-overlay').classList.add('open');
});
document.getElementById('close-settings').addEventListener('click', () => {
  document.getElementById('settings-overlay').classList.remove('open');
  const val = parseInt(document.getElementById('refresh-interval').value) || 5;
  localStorage.setItem('refreshMin', val);
  refreshMs = val * 60000;
});
document.getElementById('reset-storage').addEventListener('click', () => {
  localStorage.clear();
  location.reload();
});

// ── Init ──
async function init() {
  let data;
  try {
    const resp = await fetch(DATA_URL + '?t=' + Date.now());
    if (!resp.ok) throw new Error(resp.status);
    data = await resp.json();
  } catch (e) {
    data = EMBEDDED_DATA;
  }
  if (!data) {
    const el = document.getElementById('loading');
    el.innerHTML = '<p style="color:var(--red)">No data available. Check data.json.</p>';
    return;
  }
  currentData = data;
  renderCore(data);
  setTimeout(() => renderDeferred(data), 2000);
}

function renderCore(data) {
  renderQuickStats(data);
  renderRegimeSummary(data);
  renderConditionCards(data);
  renderGauge(data);
  document.getElementById('loading').style.display = 'none';
}

function renderDeferred(data) {
  renderHoldings(data);
  renderWarRoom(data);
  renderNewsTicker(data);
}

init();
setInterval(() => init(), refreshMs);
